import anthropic, json

client = anthropic.Anthropic()

def identify_indemnity_gaps_and_mitigations(
    vendor_indemnity_scope: str,
    enterprise_use_cases: list[dict],  # [{name, prompt_data_types, client_facing, fine_tuning}]
) -> dict:
    """
    Map enterprise use cases against vendor indemnity scope to identify
    which use cases carry unindemnified IP risk, and recommend mitigations.
    """
    prompt = f"""
You are an enterprise IP risk analyst.

AI vendor indemnity scope: {vendor_indemnity_scope}

Enterprise use cases to assess:
{json.dumps(enterprise_use_cases, indent=2)}

For each use case, determine:
1. Whether it falls within the vendor indemnity scope
2. If not, what is the magnitude of unindemnified risk
3. What mitigations reduce the risk (operational controls, insurance, contractual)

Return ONLY JSON:
{{
  "use_case_assessments": [
    {{
      "use_case_name": "<string>",
      "in_scope": true | false,
      "gap_description": "<string or null>",
      "unindemnified_risk": "none" | "low" | "medium" | "high",
      "mitigations": ["<string>", ...]
    }}
  ],
  "overall_gap_severity": "low" | "medium" | "high",
  "priority_negotiation_items": ["<string>", ...]
}}
""".strip()

    response = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=800,
        messages=[{"role": "user", "content": prompt}]
    )
    return json.loads(response.content[0].text)


result = identify_indemnity_gaps_and_mitigations(
    vendor_indemnity_scope="Covers third-party IP claims on model outputs used per AUP. Excludes customer-provided content and fine-tuning.",
    enterprise_use_cases=[
        {"name": "Marketing copy generation", "prompt_data_types": ["brand guidelines", "product specs"], "client_facing": False, "fine_tuning": False},
        {"name": "Legal contract review", "prompt_data_types": ["client contracts (verbatim)"], "client_facing": True, "fine_tuning": False},
        {"name": "Custom sales model", "prompt_data_types": ["CRM data", "historical emails"], "client_facing": True, "fine_tuning": True},
    ],
)
print(json.dumps(result, indent=2))
